mapper.select:

where v.scene_id = #{sceneId}
order by v.version_id desc
limit 1


where s.active_version_id = v.version_id
  and v.scene_id = #{sceneId}
limit 1


where v.scene_id = #{sceneId}
  and v.version_id < #{versionId}
order by v.version_id desc
limit 1

select snapshot_id, version_id, snapshot_type, object_code, object_name, snapshot_json, sort_no, create_by, create_time from cost_publish_snapshot where version_id = #{versionId}
and snapshot_type = #{snapshotType}
order by sort_no asc, snapshot_id asc
